  messages: Message[];
  updatedAt: Date;
}

export interface ChatState {
  currentSession: ChatSession | null;
  messages: Message[];
  isLoading: boolean;
  error: string | null;
}

export interface GenerationResponse {
  success: boolean;
  chatUrl?: string;
  previewUrl?: string;
  chatId?: string;
  error?: string;
}

