export const formatRelativeTime = (date: Date): string => {
  const now = new Date();
  const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);

  if (diffInSeconds < 60) return 'Just now';
  if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
  if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
  return date.toLocaleDateString();
};

export const generateId = (): string => {
  return Math.random().toString(36).substring(2, 9);
};

import { GenerationResponse } from '../types';
import { generateId } from '../lib/utils/format';

// Simulates the server action
export const generateComponentAction = async (message: string): Promise<GenerationResponse> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve({
        success: true,
        chatId: generateId(),
        chatUrl: '/chat/' + generateId(),
        previewUrl: 'about:blank', // In a real app, this would be a blob URL or deployed URL
      });
    }, 4500); // Simulate network/generation latency
  });
};

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { AppState, V0Model } from '../types';
import { SIDEBAR_CONFIG } from '../constants';

interface AppContextType extends AppState {
  setSidebarWidth: (width: number) => void;
  setSelectedModel: (model: string) => void;
  setIsGenerating: (isGenerating: boolean) => void;
  setPreviewUrl: (url: string | null) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider = ({ children }: { children: ReactNode }) => {
  const [sidebarWidth, setSidebarWidth] = useState(SIDEBAR_CONFIG.DEFAULT_WIDTH);
  const [selectedModel, setSelectedModel] = useState<string>('v0-1.5-md');
  const [isGenerating, setIsGenerating] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const [features] = useState({
    imageGeneration: true,
    codeExport: true,
    realTimePreview: true,
  });

  return (
    <AppContext.Provider
      value={{
        sidebarWidth,
        setSidebarWidth,
        selectedModel,
        setSelectedModel,
        isGenerating,
        setIsGenerating,
        previewUrl,
        setPreviewUrl,
        features
      }}
    >
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React, { createContext, useContext, useReducer, ReactNode } from 'react';
import { ChatState, Message } from '../types';

type Action =
  | { type: 'ADD_MESSAGE'; payload: Message }
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'CLEAR_MESSAGES' };

const initialState: ChatState = {
  currentSession: null,
  messages: [],
  isLoading: false,
  error: null,
};

const chatReducer = (state: ChatState, action: Action): ChatState => {
  switch (action.type) {
    case 'ADD_MESSAGE':
      return {
        ...state,
        messages: [...state.messages, action.payload],
      };
    case 'SET_LOADING':
      return {
        ...state,
        isLoading: action.payload,
      };
    case 'SET_ERROR':
      return {
        ...state,
        error: action.payload,
      };
    case 'CLEAR_MESSAGES':
        return {
            ...state,
            messages: []
        }
    default:
      return state;
  }
};

interface ChatContextType extends ChatState {
  addMessage: (message: Message) => void;
  setLoading: (isLoading: boolean) => void;
  setError: (error: string | null) => void;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export const ChatProvider = ({ children }: { children: ReactNode }) => {
  const [state, dispatch] = useReducer(chatReducer, initialState);

  const addMessage = (message: Message) => dispatch({ type: 'ADD_MESSAGE', payload: message });
  const setLoading = (isLoading: boolean) => dispatch({ type: 'SET_LOADING', payload: isLoading });
  const setError = (error: string | null) => dispatch({ type: 'SET_ERROR', payload: error });

  return (
    <ChatContext.Provider value={{ ...state, addMessage, setLoading, setError }}>
      {children}
    </ChatContext.Provider>
  );
};

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) throw new Error('useChat must be used within ChatProvider');
  return context;
};

