import { GoogleGenAI } from "@google/genai";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

interface GenerateOptions {
    useSearch?: boolean;
    useThinking?: boolean;
    systemInstruction?: string;
}

export const generateContent = async (
    prompt: string,
    imageBase64: string | null,
    options: GenerateOptions
) => {
    let modelId = 'gemini-3-flash-preview'; // Default for basic tasks and audio

    // Logic for model selection based on features
    if (options.useThinking) {
        modelId = 'gemini-3-pro-preview';
    } else if (imageBase64) {
        modelId = 'gemini-3-pro-preview'; // Image understanding requires Pro per prompt
    } else if (options.useSearch) {
        modelId = 'gemini-3-flash-preview'; // Search using Flash per prompt
    } else {
        // Default chatbot behavior - prompt says "Add a chat bot ... using gemini-3-pro-preview"
        // But for "basic text tasks" logic in system prompt suggests flash.
        // User prompt: "Add a chat bot ... using gemini-3-pro-preview"
        modelId = 'gemini-3-pro-preview';
    }

    const config: any = {
        systemInstruction: options.systemInstruction || "You are a helpful AI assistant. If asked to generate code, provide clean, modern React + Tailwind CSS code.",
    };

    if (options.useThinking) {
        config.thinkingConfig = { thinkingBudget: 32768 };
        // Do NOT set maxOutputTokens
    }

    if (options.useSearch) {
        config.tools = [{ googleSearch: {} }];
    }

    const parts: any[] = [];

    if (imageBase64) {
        // Extract base64 data and mimeType if possible, or assume png/jpeg
        // Assuming the input is a full data URL "data:image/png;base64,..."
        const match = imageBase64.match(/^data:(.+);base64,(.+)$/);
        if (match) {
            parts.push({
                inlineData: {
                    mimeType: match[1],
                    data: match[2]
                }
            });
        }
    }

    parts.push({ text: prompt });

    try {
        const response = await ai.models.generateContent({
            model: modelId,
            contents: { parts },
            config: config
        });

        return {
            text: response.text,
            groundingMetadata: response.candidates?.[0]?.groundingMetadata
        };
    } catch (error) {
        console.error("Gemini API Error:", error);
        throw error;
    }
};

export const transcribeAudio = async (audioBase64: string) => {
    // Model: gemini-3-flash-preview for audio transcription
    const match = audioBase64.match(/^data:(.+);base64,(.+)$/);
    const mimeType = match ? match[1] : 'audio/wav';
    const data = match ? match[2] : audioBase64;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { mimeType, data } },
                    { text: "Transcribe this audio exactly. Do not add any other text." }
                ]
            }
        });
        return response.text;
    } catch (error) {
        console.error("Transcription Error:", error);
        throw error;
    }
};

import React, { useState, useRef } from 'react';
import { Sparkles, Paperclip, ArrowUp, Mic, Globe, Brain, X } from 'lucide-react';
import { useChat } from '../../../providers/chat-provider';
import { useApp } from '../../../providers/app-provider';
import { generateContent, transcribeAudio } from '../../../services/ai';
import { generateId } from '../../../lib/utils/format';
import { ModelSelector } from './model-selector';

export const ChatInput = () => {
  const [input, setInput] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [useSearch, setUseSearch] = useState(false);
  const [useThinking, setUseThinking] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);

  const { addMessage, setLoading, isLoading } = useChat();
  const { setIsGenerating, setPreviewUrl } = useApp();

  const handleInput = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    adjustHeight();
  };

  const adjustHeight = () => {
      if (textareaRef.current) {
          textareaRef.current.style.height = 'auto';
          textareaRef.current.style.height = `${Math.max(96, textareaRef.current.scrollHeight)}px`;
      }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (e) => chunks.push(e.data);
      recorder.onstop = async () => {
        const blob = new Blob(chunks, { type: 'audio/webm' }); // Use webm for browser compatibility
        const reader = new FileReader();
        reader.onloadend = async () => {
            const base64Audio = reader.result as string;
            setLoading(true);
            try {
                const text = await transcribeAudio(base64Audio);
                if (text) {
                    setInput((prev) => prev + (prev ? ' ' : '') + text);
                    adjustHeight();
                }
            } catch (err) {
                console.error("Transcription failed", err);
            } finally {
                setLoading(false);
            }
        };
        reader.readAsDataURL(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    } catch (err) {
      console.error("Microphone access denied", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const handleSubmit = async () => {
    if ((!input.trim() && !selectedImage) || isLoading) return;

    const userMessage = input;
    const currentImage = selectedImage;

    // Reset state
    setInput('');
    setSelectedImage(null);
    if (textareaRef.current) textareaRef.current.style.height = '96px';

    // 1. Add User Message
    addMessage({
      id: generateId(),
      role: 'user',
      content: userMessage,
      timestamp: new Date(),
      attachment: currentImage ? { type: 'image', data: currentImage } : undefined
    });

    // 2. Set Loading States
    setLoading(true);
    setIsGenerating(true);

    try {
      // 3. Call Real Gemini API
      const response = await generateContent(userMessage, currentImage, {
          useSearch,
          useThinking
      });

      if (response && response.text) {
        addMessage({
          id: generateId(),
          role: 'assistant',
          content: response.text,
          timestamp: new Date(),
          groundingMetadata: response.groundingMetadata
        });
      }
    } catch (err) {
      console.error(err);
      addMessage({
          id: generateId(),
          role: 'assistant',
          content: "Sorry, I encountered an error processing your request.",
          timestamp: new Date()
      });
    } finally {
      setLoading(false);
      setIsGenerating(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className="p-4 border-t border-interactive-border bg-primary-background">
      <div className="relative rounded-xl border border-interactive-border bg-surface focus-within:ring-1 focus-within:ring-white/20 transition-all">
        {selectedImage && (
            <div className="p-3 pb-0">
                <div className="relative inline-block">
                    <img src={selectedImage} alt="Upload" className="h-16 w-16 object-cover rounded-md border border-interactive-border" />
                    <button 
                        onClick={() => setSelectedImage(null)}
                        className="absolute -top-2 -right-2 bg-status-error text-white rounded-full p-0.5 hover:bg-red-600"
                    >
                        <X className="w-3 h-3" />
                    </button>
                </div>
            </div>
        )}

        <textarea
          ref={textareaRef}
          value={input}
          onChange={handleInput}
          onKeyDown={handleKeyDown}
          placeholder={isRecording ? "Listening..." : "Ask v0 clone..."}
          className="w-full bg-transparent text-text-primary text-sm p-3 min-h-[96px] max-h-[200px] resize-none focus:outline-none placeholder:text-text-muted"
          disabled={isLoading || isRecording}
        />

        <div className="absolute bottom-2 left-2 flex items-center space-x-2">
             <button 
                onClick={() => setUseSearch(!useSearch)}
                className={`p-1.5 rounded-md transition-colors ${useSearch ? 'bg-status-info/20 text-status-info' : 'text-text-muted hover:text-text-primary hover:bg-interactive-hover'}`}
                title="Search Grounding"
             >
                 <Globe className="w-4 h-4" />
             </button>
             <button 
                onClick={() => setUseThinking(!useThinking)}
                className={`p-1.5 rounded-md transition-colors ${useThinking ? 'bg-purple-500/20 text-purple-400' : 'text-text-muted hover:text-text-primary hover:bg-interactive-hover'}`}
                title="Thinking Mode"
             >
                 <Brain className="w-4 h-4" />
             </button>
        </div>

        <div className="absolute bottom-2 right-2 flex items-center space-x-2">
           <input 
              type="file" 
              accept="image/*" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleImageSelect}
           />
           <button 
              onClick={() => fileInputRef.current?.click()}
              className="p-1.5 text-text-muted hover:text-text-primary hover:bg-interactive-hover rounded-md transition-colors"
           >
             <Paperclip className="w-5 h-5" />
           </button>

           <button 
             onMouseDown={startRecording}
             onMouseUp={stopRecording}
             onMouseLeave={stopRecording}
             className={`p-1.5 rounded-md transition-colors ${isRecording ? 'text-status-error animate-pulse' : 'text-text-muted hover:text-text-primary hover:bg-interactive-hover'}`}
           >
             <Mic className="w-5 h-5" />
           </button>

           <button 
             onClick={handleSubmit}
             disabled={(!input.trim() && !selectedImage) || isLoading}
             className={`p-1.5 rounded-md transition-colors ${
               (input.trim() || selectedImage) && !isLoading
                ? 'bg-interactive-primary text-black hover:opacity-90' 
                : 'bg-interactive-hover text-text-muted cursor-not-allowed'
             }`}
           >
             <ArrowUp className="w-5 h-5" />
           </button>
        </div>
      </div>
      <ModelSelector />
    </div>
  );
};

import React from 'react';
import { Message } from '../../../types';
import { formatRelativeTime } from '../../../lib/utils/format';
import { Bot, User, Globe } from 'lucide-react';
import { FileExplorer } from '../files/file-explorer';

export const ChatMessage: React.FC<{ message: Message }> = ({ message }) => {
  const isUser = message.role === 'user';

  // Helper to extract URLs from grounding chunks
  const getGroundingUrls = (chunks: any[]) => {
      if (!chunks) return [];
      return chunks.flatMap(chunk => {
          if (chunk.web?.uri) return [{ uri: chunk.web.uri, title: chunk.web.title }];
          return [];
      });
  };

  const groundingUrls = message.groundingMetadata?.groundingChunks 
      ? getGroundingUrls(message.groundingMetadata.groundingChunks)
      : [];

  return (
    <div className={`flex w-full ${isUser ? 'justify-end' : 'justify-start'} mb-6`}>
      <div className={`flex flex-col max-w-[85%] ${isUser ? 'items-end' : 'items-start'}`}>

        <div className={`flex gap-3 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
                isUser ? 'bg-surface-elevated' : 'bg-black border border-white/10'
            }`}>
                {isUser ? <User className="w-5 h-5 text-text-muted" /> : <Bot className="w-5 h-5 text-text-primary" />}
            </div>

            <div className={`flex flex-col gap-2 ${isUser ? 'items-end' : 'items-start'}`}>
                {message.attachment && message.attachment.type === 'image' && (
                    <div className="mb-2">
                        <img 
                            src={message.attachment.data} 
                            alt="User upload" 
                            className="max-w-xs rounded-lg border border-interactive-border" 
                        />
                    </div>
                )}

                <div className={`relative px-4 py-3 rounded-lg text-sm leading-relaxed whitespace-pre-wrap ${
                isUser 
                    ? 'bg-interactive-active text-text-primary' 
                    : 'bg-transparent text-text-primary'
                }`}>
                {message.content}
                </div>
            </div>
        </div>

        {/* Search Grounding Sources */}
        {!isUser && groundingUrls.length > 0 && (
             <div className="mt-2 ml-11 flex flex-wrap gap-2">
                 {groundingUrls.map((url: any, idx: number) => (
                     <a 
                        key={idx} 
                        href={url.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center space-x-1 px-2 py-1 rounded bg-surface-elevated border border-interactive-border hover:bg-interactive-hover transition-colors text-xs text-text-secondary truncate max-w-[200px]"
                     >
                         <Globe className="w-3 h-3 text-status-info" />
                         <span className="truncate">{url.title || url.uri}</span>
                     </a>
                 ))}
             </div>
        )}

        {!isUser && (
            <div className="mt-1 ml-11">
                <span className="text-xs text-text-muted">{formatRelativeTime(message.timestamp)}</span>
            </div>
        )}

        {!isUser && message.content.includes("structure") && (
            <div className="w-full pl-11 mt-2">
                <FileExplorer />
            </div>
        )}

      </div>
    </div>
  );
};

