    // 2. Set Loading States
    setLoading(true);
    setIsGenerating(true);

    try {
      // 3. Call Real Gemini API - Always use Search and Thinking as requested
      const response = await generateContent(userMessage, currentImage, {
          useSearch: true,
          useThinking: true
      });

      if (response && response.text) {
        addMessage({
          id: generateId(),
          role: 'assistant',
          content: response.text,
          timestamp: new Date(),
