// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

interface GenerateOptions {
    useSearch?: boolean;
    useThinking?: boolean;
    systemInstruction?: string;
}

export const generateContent = async (
    prompt: string,
    imageBase64: string | null,
    options: GenerateOptions
) => {
    // Set Gemini 3 Pro as the main AI model for app building and complex tasks
    const modelId = 'gemini-3-pro-preview';

    const config: any = {
        systemInstruction: options.systemInstruction || `You are PantheraVIBEZ, an expert frontend engineer and UI designer. 
Your goal is to help users build web applications using React, Tailwind CSS, and Lucide React icons.
When asked to generate code:
1. Provide complete, working, and interactive React components.
2. Use Tailwind CSS for styling.
3. Ensure the code is responsive and accessible.
4. Do not omit code for brevity; provide the full implementation.`,
    };

    if (options.useThinking) {
        config.thinkingConfig = { thinkingBudget: 32768 };
        // Do NOT set maxOutputTokens when using thinking
    }

    if (options.useSearch) {
        config.tools = [{ googleSearch: {} }];
    }

    const parts: any[] = [];

    if (imageBase64) {
        // Extract base64 data and mimeType if possible, or assume png/jpeg
        // Assuming the input is a full data URL "data:image/png;base64,..."
        const match = imageBase64.match(/^data:(.+);base64,(.+)$/);
        if (match) {
            parts.push({
                inlineData: {
                    mimeType: match[1],
                    data: match[2]
                }
            });
        }
    }

    parts.push({ text: prompt });

    try {
        const response = await ai.models.generateContent({
            model: modelId,
            contents: { parts },
            config: config
        });

        return {
            text: response.text,
            groundingMetadata: response.candidates?.[0]?.groundingMetadata
        };
    } catch (error) {
        console.error("Gemini API Error:", error);
        throw error;
    }
};

export const transcribeAudio = async (audioBase64: string) => {
    // Keep gemini-3-flash-preview for fast audio transcription
    const match = audioBase64.match(/^data:(.+);base64,(.+)$/);
    const mimeType = match ? match[1] : 'audio/wav';
    const data = match ? match[2] : audioBase64;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { mimeType, data } },
                    { text: "Transcribe this audio exactly. Do not add any other text." }
                ]
            }
        });
        return response.text;
    } catch (error) {
        console.error("Transcription Error:", error);
        throw error;
    }
};

