        <div className="flex-1 overflow-auto bg-[#0a0a0a] relative custom-scrollbar">
            {generatedCode ? (
                <div className="p-6">
                    <pre className="font-mono text-sm leading-relaxed tab-4">
                        <HighlightedCode code={generatedCode} />
