import React, { createContext, useContext, useState, ReactNode } from 'react';
import { AppState, V0Model } from '../types';
import { SIDEBAR_CONFIG } from '../constants';

export interface Team {
  id: string;
  name: string;
  avatarUrl: string;
  type: 'personal' | 'team';
}

export interface Project {
  id: string;
  name: string;
  privacy: 'public' | 'private';
  updatedAt: Date;
}

interface AppContextType extends AppState {
  setSidebarWidth: (width: number) => void;
  setSelectedModel: (model: string) => void;
  setIsGenerating: (isGenerating: boolean) => void;
  setPreviewUrl: (url: string | null) => void;
  setGeneratedCode: (code: string | null) => void;
  isFullscreen: boolean;
  setIsFullscreen: (isFullscreen: boolean) => void;
  isSettingsOpen: boolean;
  setIsSettingsOpen: (isOpen: boolean) => void;
  isCodeViewOpen: boolean;
  setIsCodeViewOpen: (isOpen: boolean) => void;
  isGithubModalOpen: boolean;
  setIsGithubModalOpen: (isOpen: boolean) => void;
  isShareModalOpen: boolean;
  setIsShareModalOpen: (isOpen: boolean) => void;
  currentTeam: Team;
  setCurrentTeam: (team: Team) => void;
  currentProject: Project;
  setCurrentProject: (project: Project) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const DEFAULT_TEAM: Team = {
  id: 'personal',
  name: 'Personal',
  avatarUrl: 'https://picsum.photos/40/40',
  type: 'personal'
};

const DEFAULT_PROJECT: Project = {
  id: 'p1',
  name: 'v0 Community Starter',
  privacy: 'private',
  updatedAt: new Date()
};

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [sidebarWidth, setSidebarWidth] = useState(SIDEBAR_CONFIG.DEFAULT_WIDTH);
  const [selectedModel, setSelectedModel] = useState<string>('gemini-3-pro-preview');
  const [isGenerating, setIsGenerating] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [generatedCode, setGeneratedCode] = useState<string | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isCodeViewOpen, setIsCodeViewOpen] = useState(false);
  const [isGithubModalOpen, setIsGithubModalOpen] = useState(false);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);
  const [currentTeam, setCurrentTeam] = useState<Team>(DEFAULT_TEAM);
  const [currentProject, setCurrentProject] = useState<Project>(DEFAULT_PROJECT);

  const [features] = useState({
    imageGeneration: true,
    codeExport: true,
    realTimePreview: true,
  });

  return (
    <AppContext.Provider
      value={{
        sidebarWidth,
        setSidebarWidth,
        selectedModel,
        setSelectedModel,
        isGenerating,
        setIsGenerating,
        previewUrl,
        setPreviewUrl,
        generatedCode,
        setGeneratedCode,
        features,
        isFullscreen,
        setIsFullscreen,
        isSettingsOpen,
        setIsSettingsOpen,
        isCodeViewOpen,
        setIsCodeViewOpen,
        isGithubModalOpen,
        setIsGithubModalOpen,
        isShareModalOpen,
        setIsShareModalOpen,
        currentTeam,
        setCurrentTeam,
        currentProject,
        setCurrentProject
      }}
    >
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React, { useState, useRef, useEffect } from 'react';
import { ChevronsUpDown, Check, Plus } from 'lucide-react';
import { useApp, Team } from '../../../providers/app-provider';

export const TeamSelector = () => {
    const { currentTeam, setCurrentTeam } = useApp();
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    // Mock Teams
    const teams: Team[] = [
        { id: 'personal', name: 'Personal', avatarUrl: 'https://picsum.photos/40/40', type: 'personal' },
        { id: 'acme', name: 'Acme Corp', avatarUrl: 'https://picsum.photos/41/41', type: 'team' },
        { id: 'startup', name: 'My Startup', avatarUrl: 'https://picsum.photos/42/42', type: 'team' }
    ];

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        if (isOpen) document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [isOpen]);

    return (
        <div className="relative" ref={dropdownRef}>
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center space-x-2 hover:bg-interactive-hover px-2 py-1 rounded transition-colors group"
            >
                <div className="w-5 h-5 rounded-full bg-gradient-to-tr from-purple-500 to-blue-500 overflow-hidden border border-white/10">
                    <img src={currentTeam.avatarUrl} alt={currentTeam.name} className="w-full h-full object-cover" />
                </div>
                <span className="text-text-primary font-medium text-sm">{currentTeam.name}</span>
                <ChevronsUpDown className="w-3 h-3 text-text-muted group-hover:text-text-primary" />
            </button>

            {isOpen && (
                <div className="absolute top-full left-0 mt-2 w-60 bg-[#1a1a1a] border border-[#333] rounded-lg shadow-xl z-50 overflow-hidden animate-[fadeIn_0.1s_ease-out]">
                    <div className="p-2">
                        <div className="px-2 py-1.5 text-xs font-medium text-gray-500">Personal Account</div>
                        <button 
                            onClick={() => { setCurrentTeam(teams[0]); setIsOpen(false); }}
                            className="w-full flex items-center justify-between px-2 py-1.5 hover:bg-[#2a2a2a] rounded-md group"
                        >
                            <div className="flex items-center space-x-2">
                                <div className="w-5 h-5 rounded-full overflow-hidden">
                                     <img src={teams[0].avatarUrl} className="w-full h-full object-cover" />
                                </div>
                                <span className="text-sm text-white">{teams[0].name}</span>
                            </div>
                            {currentTeam.id === teams[0].id && <Check className="w-3.5 h-3.5 text-white" />}
                        </button>

                        <div className="my-2 h-px bg-[#333]" />

                         <div className="px-2 py-1.5 text-xs font-medium text-gray-500">Teams</div>
                         {teams.slice(1).map(team => (
                             <button 
                                key={team.id}
                                onClick={() => { setCurrentTeam(team); setIsOpen(false); }}
                                className="w-full flex items-center justify-between px-2 py-1.5 hover:bg-[#2a2a2a] rounded-md group"
                            >
                                <div className="flex items-center space-x-2">
                                    <div className="w-5 h-5 rounded-md overflow-hidden bg-gray-700 flex items-center justify-center text-xs">
                                         {team.avatarUrl ? <img src={team.avatarUrl} className="w-full h-full object-cover" /> : team.name[0]}
                                    </div>
                                    <span className="text-sm text-white">{team.name}</span>
                                </div>
                                {currentTeam.id === team.id && <Check className="w-3.5 h-3.5 text-white" />}
                            </button>
                         ))}

                         <button className="w-full flex items-center space-x-2 px-2 py-2 mt-1 hover:bg-[#2a2a2a] rounded-md text-gray-400 hover:text-white transition-colors">
                            <div className="w-5 h-5 rounded-md border border-gray-600 border-dashed flex items-center justify-center">
                                <Plus className="w-3 h-3" />
                            </div>
                            <span className="text-sm">Create Team</span>
                         </button>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { ChevronsUpDown, Search, Plus, Folder, Check } from 'lucide-react';
import { useApp, Project } from '../../../providers/app-provider';
import { formatRelativeTime } from '../../../lib/utils/format';

export const ProjectSelector = () => {
    const { currentProject, setCurrentProject } = useApp();
    const [isOpen, setIsOpen] = useState(false);
    const [search, setSearch] = useState('');
    const dropdownRef = useRef<HTMLDivElement>(null);

    // Mock Projects
    const projects: Project[] = [
        { id: 'p1', name: 'v0 Community Starter', privacy: 'private', updatedAt: new Date() },
        { id: 'p2', name: 'E-commerce Dashboard', privacy: 'public', updatedAt: new Date(Date.now() - 1000 * 60 * 60 * 2) },
        { id: 'p3', name: 'Portfolio Site 2025', privacy: 'private', updatedAt: new Date(Date.now() - 1000 * 60 * 60 * 24 * 3) },
        { id: 'p4', name: 'Landing Page Test', privacy: 'public', updatedAt: new Date(Date.now() - 1000 * 60 * 60 * 24 * 7) },
    ];

    const filteredProjects = projects.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        if (isOpen) document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [isOpen]);

    return (
        <div className="relative" ref={dropdownRef}>
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center space-x-1 hover:bg-interactive-hover px-2 py-1 rounded transition-colors group max-w-[200px]"
            >
                 <span className="text-text-primary font-medium text-sm truncate">{currentProject.name}</span>
                 <ChevronsUpDown className="w-3 h-3 text-text-muted group-hover:text-text-primary shrink-0" />
            </button>

            {isOpen && (
                <div className="absolute top-full left-0 mt-2 w-72 bg-[#1a1a1a] border border-[#333] rounded-lg shadow-xl z-50 overflow-hidden animate-[fadeIn_0.1s_ease-out]">
                    <div className="p-2 border-b border-[#333]">
                        <div className="relative">
                            <Search className="absolute left-2 top-2 w-3.5 h-3.5 text-gray-500" />
                            <input 
                                type="text" 
                                placeholder="Search projects..." 
                                value={search}
                                onChange={(e) => setSearch(e.target.value)}
                                autoFocus
                                className="w-full bg-[#0a0a0a] border border-[#333] rounded-md pl-8 pr-3 py-1.5 text-xs text-white focus:outline-none focus:border-blue-500 placeholder:text-gray-600"
                            />
                        </div>
                    </div>

                    <div className="max-h-64 overflow-y-auto p-1 custom-scrollbar">
                        <div className="px-2 py-1.5 text-xs font-medium text-gray-500">Recent Projects</div>
                        {filteredProjects.length > 0 ? (
                            filteredProjects.map(project => (
                                <button 
                                    key={project.id}
                                    onClick={() => { setCurrentProject(project); setIsOpen(false); }}
                                    className="w-full flex items-center justify-between px-2 py-2 hover:bg-[#2a2a2a] rounded-md group text-left"
                                >
                                    <div className="flex items-center space-x-2.5 overflow-hidden">
                                        <Folder className="w-4 h-4 text-gray-500 shrink-0" />
                                        <div className="overflow-hidden">
                                            <div className="text-sm text-white truncate">{project.name}</div>
                                            <div className="text-[10px] text-gray-500 flex items-center space-x-1">
                                                <span>{formatRelativeTime(project.updatedAt)}</span>
                                            </div>
                                        </div>
                                    </div>
                                    {currentProject.id === project.id && <Check className="w-3.5 h-3.5 text-white shrink-0" />}
                                </button>
                            ))
                        ) : (
                            <div className="px-4 py-3 text-center text-xs text-gray-500">No projects found</div>
                        )}
