export const ChatMessage: React.FC<{ message: Message }> = ({ message }) => {
  const isUser = message.role === 'user';

  // Helper to extract URLs from grounding chunks
  const getGroundingUrls = (chunks: any[]) => {
      if (!chunks) return [];
      return chunks.flatMap(chunk => {
          if (chunk.web?.uri) return [{ uri: chunk.web.uri, title: chunk.web.title }];
          return [];
      });
  };

  const groundingUrls = message.groundingMetadata?.groundingChunks 
      ? getGroundingUrls(message.groundingMetadata.groundingChunks)
      : [];

  // Parse for Plan content
  const planMatch = message.content.match(/<plan>([\s\S]*?)<\/plan>/);
  const displayContent = planMatch ? message.content.replace(/<plan>[\s\S]*?<\/plan>/, '') : message.content;
  const planContent = planMatch ? planMatch[1] : null;

  return (
    <div className={`flex w-full ${isUser ? 'justify-end' : 'justify-start'} mb-6`}>
      <div className={`flex flex-col max-w-[85%] ${isUser ? 'items-end' : 'items-start'}`}>

        <div className={`flex gap-3 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
                isUser ? 'bg-surface-elevated' : 'bg-black border border-white/10'
            }`}>
                {isUser ? <User className="w-5 h-5 text-text-muted" /> : <Bot className="w-5 h-5 text-text-primary" />}
            </div>

            <div className={`flex flex-col gap-2 ${isUser ? 'items-end' : 'items-start'}`}>
                {message.attachment && message.attachment.type === 'image' && (
                    <div className="mb-2">
                        <img 
                            src={message.attachment.data} 
                            alt="User upload" 
                            className="max-w-xs rounded-lg border border-interactive-border" 
                        />
                    </div>
                )}

                {/* Normal Text Content */}
                {displayContent.trim() && (
                    <div className={`relative px-4 py-3 rounded-lg text-sm leading-relaxed whitespace-pre-wrap ${
                    isUser 
                        ? 'bg-interactive-active text-text-primary' 
                        : 'bg-transparent text-text-primary'
                    }`}>
                    {displayContent}
                    </div>
                )}

                {/* Plan Card */}
                {planContent && (
                    <div className="mt-2 w-full max-w-2xl bg-[#0f172a] border border-blue-900/50 rounded-xl overflow-hidden shadow-2xl">
                        <div className="px-4 py-3 border-b border-blue-900/30 bg-blue-900/20 flex items-center space-x-2">
                             <Compass className="w-5 h-5 text-blue-400" />
                             <span className="font-medium text-blue-100 text-sm">Proposed Project Plan</span>
                        </div>
                        <div className="p-5 text-sm text-gray-300 leading-relaxed whitespace-pre-wrap font-mono">
                            {planContent}
                        </div>
                        <div className="px-4 py-3 bg-blue-900/10 border-t border-blue-900/30 flex items-center justify-between">
                            <span className="text-xs text-blue-300/70">Type "Approve" to start building</span>
                            <div className="flex items-center space-x-2">
                                <span className="flex items-center text-xs text-green-400 bg-green-400/10 px-2 py-1 rounded">
                                    <CheckCircle className="w-3 h-3 mr-1" />
                                    Reviewing
                                </span>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>

        {/* Search Grounding Sources */}
        {!isUser && groundingUrls.length > 0 && (
             <div className="mt-2 ml-11 flex flex-wrap gap-2">
                 {groundingUrls.map((url: any, idx: number) => (
                     <a 
                        key={idx} 
                        href={url.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center space-x-1 px-2 py-1 rounded bg-surface-elevated border border-interactive-border hover:bg-interactive-hover transition-colors text-xs text-text-secondary truncate max-w-[200px]"
                     >
                         <Globe className="w-3 h-3 text-status-info" />
                         <span className="truncate">{url.title || url.uri}</span>
                     </a>
                 ))}
             </div>
        )}

        {!isUser && (
            <div className="mt-1 ml-11">
                <span className="text-xs text-text-muted">{formatRelativeTime(message.timestamp)}</span>
            </div>
        )}

        {!isUser && message.content.includes("structure") && !planContent && (
            <div className="w-full pl-11 mt-2">
                <FileExplorer />
            </div>
        )}

      </div>
    </div>
  );
};

import { useChat } from '../providers/chat-provider';
import { useApp } from '../providers/app-provider';
import { generateContent } from '../services/ai';
import { extractCode } from '../lib/utils/parsing';
import { generateId } from '../lib/utils/format';
import { PLANNING_SYSTEM_PROMPT } from '../lib/templates/plan-prompt';
import { PREVIEW_SYSTEM_PROMPT } from '../lib/templates/html-preview';

export const useCodeGenerator = () => {
  const { addMessage, setLoading, isLoading, messages } = useChat();
  const { setIsGenerating, setPreviewUrl, setGeneratedCode, selectedModel, isPlanningMode, setIsPlanningMode } = useApp();

  const generate = async (userMessage: string, currentImage: string | null, isPlanningOverride?: boolean) => {
    if (!userMessage.trim() && !currentImage) return;

    // Resolve the effective mode (handle race condition of state update)
    const effectiveIsPlanning = isPlanningOverride ?? isPlanningMode;

    // 1. Add User Message
    addMessage({
      id: generateId(),
      role: 'user',
      content: userMessage,
      timestamp: new Date(),
      attachment: currentImage ? { type: 'image', data: currentImage } : undefined
    });

    // 2. Set Loading States
    setLoading(true);

    // Only set generating state if NOT in planning mode
    if (!effectiveIsPlanning) {
        setIsGenerating(true);
    }

    try {
      // Determine System Prompt
      const systemInstruction = effectiveIsPlanning ? PLANNING_SYSTEM_PROMPT : PREVIEW_SYSTEM_PROMPT;

      // 3. Call Gemini API
      const response = await generateContent(
        userMessage, 
        currentImage, 
        messages, // Pass full history
        selectedModel, 
        {
          useSearch: true,
          useThinking: true,
          systemInstruction
        }
      );

      if (response && response.text) {
        let responseText = response.text;

        // CHECK FOR SPEC GENERATION (Transition from Plan -> Code)
        const specMatch = responseText.match(/<spec>([\s\S]*?)<\/spec>/);
        if (specMatch && effectiveIsPlanning) {
             const finalSpec = specMatch[1];

             // Add the planner's confirmation message first
             addMessage({
                id: generateId(),
                role: 'assistant',
                content: "Plan approved! Starting generation...",
                timestamp: new Date()
             });

             // Switch modes
             setIsPlanningMode(false);
             setIsGenerating(true);

             // IMMEDIATELY Trigger Code Generation with the Spec
             const codeResponse = await generateContent(
                 finalSpec,
                 null,
                 [], // Clear history for the fresh start of coding to avoid confusion with the planner.
                 selectedModel,
                 {
                     useSearch: true,
                     useThinking: true,
                     systemInstruction: PREVIEW_SYSTEM_PROMPT
                 }
             );

             if (codeResponse && codeResponse.text) {
                 const code = extractCode(codeResponse.text);
                 if (code) {
                     setGeneratedCode(code);
                     setPreviewUrl('generated');
                 }

                 addMessage({
                    id: generateId(),
                    role: 'assistant',
                    content: codeResponse.text,
                    timestamp: new Date(),
                    groundingMetadata: codeResponse.groundingMetadata
                 });
             }

        } else {
            // Normal Response (Planning or Coding)

            // Extract HTML code if we are NOT in planning mode (or if mixed)
            if (!effectiveIsPlanning) {
                const code = extractCode(responseText);
                if (code) {
                    setGeneratedCode(code);
                    setPreviewUrl('generated');
                }
            }

            addMessage({
              id: generateId(),
              role: 'assistant',
              content: responseText,
              timestamp: new Date(),
              groundingMetadata: response.groundingMetadata
            });
        }
      }
    } catch (err) {
      console.error(err);
      addMessage({
        id: generateId(),
        role: 'assistant',
        content: "Sorry, I encountered an error processing your request.",
        timestamp: new Date()
      });
    } finally {
      setLoading(false);
      setIsGenerating(false);
    }
  };

  const startPlanning = async (initialMessage?: string) => {
      setIsPlanningMode(true);
      const message = initialMessage || "I want to plan a new project. Help me define the requirements.";
      // Pass 'true' to override the stale closure state of isPlanningMode
      await generate(message, null, true);
  };

  return {
    generate,
    startPlanning,
    isLoading
  };
};

import React, { useState, useRef } from 'react';
import { Paperclip, ArrowUp, Mic, X, Compass } from 'lucide-react';
import { useCodeGenerator } from '../../../hooks/use-code-generator';
import { useAudioRecorder } from '../../../hooks/use-audio-recorder';
import { useApp } from '../../../providers/app-provider';

export const ChatInput = () => {
  const [input, setInput] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const { isPlanningMode } = useApp();

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { generate, startPlanning, isLoading } = useCodeGenerator();

  const handleTranscription = (text: string) => {
    setInput((prev) => prev + (prev ? ' ' : '') + text);
    adjustHeight();
  };

  const { isRecording, isProcessing, startRecording, stopRecording } = useAudioRecorder({
    onTranscriptionComplete: handleTranscription
  });

  const handleInput = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    adjustHeight();
  };

  const adjustHeight = () => {
      if (textareaRef.current) {
          textareaRef.current.style.height = 'auto';
          textareaRef.current.style.height = `${Math.max(96, textareaRef.current.scrollHeight)}px`;
      }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async () => {
    if ((!input.trim() && !selectedImage) || isLoading || isProcessing) return;

    const userMessage = input;
    const currentImage = selectedImage;

    // Reset UI state immediately
    setInput('');
    setSelectedImage(null);
    if (textareaRef.current) textareaRef.current.style.height = '96px';

    await generate(userMessage, currentImage);
  };

  const handlePlanClick = async () => {
      if (isLoading || isProcessing) return;

      const message = input.trim() ? input.trim() : undefined;

      // Reset UI state
      setInput('');
      setSelectedImage(null);
      if (textareaRef.current) textareaRef.current.style.height = '96px';

      await startPlanning(message);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const isBusy = isLoading || isProcessing;

  return (
    <div className={`p-4 border-t border-interactive-border bg-primary-background ${isPlanningMode ? 'border-t-blue-500/30' : ''}`}>
      {isPlanningMode && (
          <div className="flex items-center space-x-2 mb-2 text-xs font-medium text-blue-400 animate-pulse">
              <Compass className="w-3.5 h-3.5" />
              <span>Planning Mode Active</span>
          </div>
      )}
      <div className={`relative rounded-xl border bg-surface focus-within:ring-1 focus-within:ring-white/20 transition-all ${isPlanningMode ? 'border-blue-500/30 shadow-[0_0_15px_rgba(59,130,246,0.1)]' : 'border-interactive-border'}`}>
        {selectedImage && (
            <div className="p-3 pb-0">
                <div className="relative inline-block">
                    <img src={selectedImage} alt="Upload" className="h-16 w-16 object-cover rounded-md border border-interactive-border" />
                    <button 
                        onClick={() => setSelectedImage(null)}
                        className="absolute -top-2 -right-2 bg-status-error text-white rounded-full p-0.5 hover:bg-red-600"
                    >
                        <X className="w-3 h-3" />
                    </button>
                </div>
            </div>
        )}

        <textarea
          ref={textareaRef}
          value={input}
          onChange={handleInput}
          onKeyDown={handleKeyDown}
          placeholder={isRecording ? "Listening..." : isProcessing ? "Transcribing..." : isPlanningMode ? "Describe your requirements..." : "Ask PantheraVIBEZ..."}
          className="w-full bg-transparent text-text-primary text-sm p-3 pb-12 min-h-[96px] max-h-[200px] resize-none focus:outline-none placeholder:text-text-muted"
          disabled={isBusy || isRecording}
        />

        {/* Left Controls: Attach & Mic */}
        <div className="absolute bottom-2 left-2 flex items-center space-x-2">
           <input 
              type="file" 
              accept="image/*" 
              className="hidden" 
              ref={fileInputRef}
              onChange={handleImageSelect}
           />
           <button 
              onClick={() => fileInputRef.current?.click()}
              className="p-1.5 text-text-muted hover:text-text-primary hover:bg-interactive-hover rounded-md transition-colors"
              disabled={isBusy}
              title="Attach Image"
           >
             <Paperclip className="w-5 h-5" />
           </button>

           <button 
             onMouseDown={startRecording}
             onMouseUp={stopRecording}
             onMouseLeave={stopRecording}
             disabled={isBusy}
             className={`p-1.5 rounded-md transition-colors ${isRecording ? 'text-status-error animate-pulse' : 'text-text-muted hover:text-text-primary hover:bg-interactive-hover'}`}
             title="Voice Input"
           >
             <Mic className="w-5 h-5" />
           </button>

           <div className="w-px h-4 bg-interactive-border mx-1" />

           <button 
             onClick={handlePlanClick}
             disabled={isBusy || isPlanningMode}
             className={`p-1.5 rounded-md transition-colors flex items-center space-x-1 ${
                 isPlanningMode 
                 ? 'text-blue-400 bg-blue-500/10' 
                 : 'text-text-muted hover:text-blue-400 hover:bg-interactive-hover'
             }`}
             title="Plan Project"
           >
             <Compass className="w-5 h-5" />
           </button>
        </div>

        {/* Right Controls: Submit */}
        <div className="absolute bottom-2 right-2 flex items-center space-x-2">
           <button 
             onClick={handleSubmit}
             disabled={(!input.trim() && !selectedImage) || isBusy}
             className={`p-1.5 rounded-md transition-colors ${
               (input.trim() || selectedImage) && !isBusy
                ? 'bg-interactive-primary text-black hover:opacity-90' 
                : 'bg-interactive-hover text-text-muted cursor-not-allowed'
             }`}
           >
             <ArrowUp className="w-5 h-5" />
           </button>
        </div>
      </div>
    </div>
  );
};
